int main(){
    int num;
    printf("请输入数的个数：");
    // 获取用户输入的值
    scanf("%d",&num);

    // 5 个值
    int* arr = (int*)malloc(sizeof(int)*num);
    int i = 0;
    for(; i < num; i++){
        arr[i] = i; // arr[i] == *(arr + i);
    }

    printf("开辟内存的指针：%p\n",arr);

    // 再加点内存
    printf("请输入新增的个数：");
    // 获取用户新输入的值
    int new_num;
    scanf("%d",&new_num); // 5
    // 原来那块内存的指针，总的大小（原来的大小+新的大小）
    int* new_arr = (int*)realloc(arr,sizeof(int)*(num+new_num));

    if(new_arr){ // = if(new_arr != NULL)
        i = num;
        for(; i < (num+new_num); i++){
            arr[i] = i; // arr[i] == *(arr + i);
        }

        printf("新开辟内存的指针：%p\n",new_arr);

        // 打印数组
        int i = 0;
        for(; i < (num + new_num); i++){
            printf("%d,%p\n",*(arr + i),arr + i);
        }

    }

    if(new_arr){
        // 如果成功了，只需要释放新的地址就行
        free(new_arr);
        new_arr = NULL;
    } else{
        // 如果没成功，释放原来的内存
        free(arr);
    }

    // 不要反复去释放，那块地址一旦被释放，就有可能会被新的应用占用，不要去再次释放。
    // free(new_arr);

    // 工作 C/C++ 精通

    getchar();
}
