(JNIEnv * env, jobject jobj){

	// 3. 获取 jclass
	jclass jcls = (*env)->GetObjectClass(env,jobj);

	// 2. 获取 jmethodID
	jmethodID j_mid = (*env)->GetMethodID(env,jcls,"add","(II)I");

	// 1. 调用 java 方法
	jint sum = (*env)->CallObjectMethod(env,jobj,j_mid,2,3);

	printf("sum = %d",sum);
}
