    // 32 怎么来的？ 18 + 4 + 8 = 30, 按照能整除最大的基本数据类型来算：32/8=4
};

int main(){
    int size = sizeof(Worker); // 24字节
    // 计算的规则：
    // 1. 按照最大的字节去计算
    // 2. 算得时候只会按照基本数据类型去算
    // 3. 首先会把所有字节数加起来， 是否能够整除最大属性(有其它结构体就按照其它结构体中所有的基本类型数据总和跟本身最大的基本数据类型比较大小)的字节数，如果不够会往上累加，一直加到能整除的位置

    printf("size = %d \n",size);
    getchar();
}

