        printf("文件打开失败");
        exit(0);// 退出程序
    }
    // 没有一个函数是可以直接拿文件大小
    // 思路：将文件的指针移动到最后，然后再去计算偏移量
    // 三个参数 SEEK_SET（开头），SEEK_CUR（当前），SEEK_END（移动到最后）
    fseek(file,0,SEEK_END);

