    for(int i = 0; i<count;i++){
        int number = va_arg(vp,int);
        sum += number;
        cout << i << "：" << number << endl;
    }

    // 结尾，释放内存
    va_end(vp);

    return sum;
}

int main(){
    int number = sum(4,1,2,4,0); // 7
    cout << number << endl;
}
