    // 插入数据
    // v.begin(); // 迭代器的开始位置
    v.insert(v.begin(),12);
    v.insert(v.begin(),22);
    v.insert(v.begin(),32);

    v.insert(v.end(),42);

    // 引用当左值当右值（修改）
    v.front() = 33;
    v.back() = 44;

    v.push_back(55);

    // 移除最后的元素，并没有返回值
    // v.pop_back();
    // 通过迭代器位置进行移除
    // v.erase(v.begin());

    // 获取数据 for 循环
    for(int i = 0; i < v.size(); i++){
        cout << v[i] << "\t"; // 越界程序宕机,clion 和 AS中不一定出错
    }
    cout << endl;
    //
    for(int i = 0; i < v.size(); i++){
        cout << v.at(i) << "\t"; // 越界抛异常 out_of_range
    }
    cout << endl;

    // 通过迭代器
    for(vector<int>::iterator it = v.begin(); it != v.end(); it++){
        cout << *it << "\t"; // 越界抛异常 out_of_range
    }
    cout << endl;
}
```

